local function calculate_hash(code)
    local sha256 = resty_sha256:new()
    sha256:update(code)
    local digest = sha256:final()
    return str.to_hex(digest)
end

local function validate_plugin_code(code)
    if type(code) ~= "string" or #code == 0 then
        return false, "Invalid plugin code: must be non-empty string"
    end
    
    if #code > 1024 * 1024 then
        return false, "Plugin code too large (max 1MB)"
    end
    
    local dangerous_patterns = {
        "os%.",
        "io%.",
        "package%.",
        "require%s*%(",
        "dofile%s*%(",
        "loadfile%s*%(",
        "debug%.",
        "getfenv",
        "setfenv",
        "_G%[",
        "rawget",
        "rawset",
        "getmetatable",
        "setmetatable",
    }
    
    for _, pattern in ipairs(dangerous_patterns) do
        if string.find(code, pattern) then
            return false, "Plugin code contains forbidden pattern: " .. pattern
        end
    end
    
    return true
end

local function load_plugin_from_redis(redis_config, plugin_name)
    local red = redis:new()
    red:set_timeout(redis_config.timeout or 1000)
    
    local ok, err = red:connect(redis_config.host or "127.0.0.1", redis_config.port or 6379)
    if not ok then
        return nil, "Failed to connect to Redis: " .. tostring(err)
    end
    
    if redis_config.password then
        local res, err = red:auth(redis_config.password)
        if not res then
            return nil, "Redis auth failed: " .. tostring(err)
        end
    end
    
    if redis_config.database then
        local res, err = red:select(redis_config.database)
        if not res then
            return nil, "Redis select database failed: " .. tostring(err)
        end
    end
    
    local plugin_key = "plugin:" .. plugin_name
    local code, err = red:get(plugin_key)
    
    if not code or code == ngx.null then
        red:set_keepalive(10000, 100)
        return nil, "Plugin not found in Redis: " .. plugin_name
    end
    
    local hash_key = "plugin:hash:" .. plugin_name
    local expected_hash, err = red:get(hash_key)
    
    red:set_keepalive(10000, 100)
    
    if expected_hash and expected_hash ~= ngx.null then
        local actual_hash = calculate_hash(code)
        if actual_hash ~= expected_hash then
            return nil, "Plugin hash mismatch - possible tampering detected"
        end
    end
    
    return code
end

local function load_plugin_from_header(header_name)
    local headers = ngx.req.get_headers()
    local code = headers[header_name]
    
    if not code then
        return nil, "Plugin code not found in header: " .. header_name
    end
    
    local decoded_code = ngx.decode_base64(code)
    if not decoded_code then
        return nil, "Failed to decode base64 plugin code from header"
    end
    
    local hash_header = header_name .. "-Hash"
    local expected_hash = headers[hash_header]
    
    if expected_hash then
        local actual_hash = calculate_hash(decoded_code)
        if actual_hash ~= expected_hash then
            return nil, "Plugin hash mismatch in header - possible tampering detected"
        end
    end
    
    return decoded_code
end

local function compile_and_sandbox(code, plugin_name)
