function _M.load_plugin(config)
    local plugin_name = config.plugin_name
    local source = config.source or "redis"
    
    if not plugin_name then
        return nil, "Plugin name is required"
    end
    
    if PLUGIN_CACHE[plugin_name] then
        ngx.log(ngx.INFO, "Loading plugin from cache: ", plugin_name)
        return PLUGIN_CACHE[plugin_name]
    end
    
    local code, err
    
