    local success, result = pcall(plugin_func)
    if not success then
        return nil, "Plugin execution failed: " .. tostring(result)
    end
    
    if config.cache ~= false then
        PLUGIN_CACHE[plugin_name] = result
    end
    
    ngx.log(ngx.INFO, "Successfully loaded plugin: ", plugin_name)
    return result
end

function _M.execute_plugin(config, ...)
    local plugin, err = _M.load_plugin(config)
    if not plugin then
        ngx.log(ngx.ERR, "Failed to load plugin: ", err)
        return nil, err
    end
    
    if type(plugin) == "function" then
        local success, result = pcall(plugin, ...)
        if not success then
            ngx.log(ngx.ERR, "Plugin execution error: ", result)
            return nil, result
        end
        return result
    elseif type(plugin) == "table" then
        if plugin.execute and type(plugin.execute) == "function" then
            local success, result = pcall(plugin.execute, ...)
            if not success then
                ngx.log(ngx.ERR, "Plugin execution error: ", result)
                return nil, result
            end
            return result
        else
            return plugin
        end
    else
        return plugin
    end
end

